    /** Orange Money — Burkina Faso */
    readonly OM_BF: "OM_BF";
    /** Moov Money — Burkina Faso */
    readonly MOOV_BF: "MOOV_BF";
    /** Wave — Burkina Faso */
    readonly WAVE_BF: "WAVE_BF";
    /** Orange Money — Mali */
    readonly OM_ML: "OM_ML";
    /** Moov Money — Mali */
    readonly MOOV_ML: "MOOV_ML";
    /** Orange Money — Sénégal */
    readonly OM_SN: "OM_SN";
    /** Free Money — Sénégal */
    readonly FREE_SN: "FREE_SN";
    /** Expresso — Sénégal */
    readonly EXPRESSO_SN: "EXPRESSO_SN";
    /** Wave — Sénégal */
    readonly WAVE_SN: "WAVE_SN";
    /** Moov Money — Togo */
    readonly MOOV_TG: "MOOV_TG";
    /** TMoney (Togocell) — Togo */
    readonly TMONEY_TG: "TMONEY_TG";
    /** Orange Money — Guinée */
    readonly OM_GN: "OM_GN";
    /** MTN Mobile Money — Guinée */
    readonly MTN_GN: "MTN_GN";
    /** Orange Money — Cameroun */
    readonly OM_CM: "OM_CM";
    /** MTN Mobile Money — Cameroun */
    readonly MTN_CM: "MTN_CM";
    /** Moov Money — Bénin */
    readonly MOOV_BJ: "MOOV_BJ";
    /** MTN Mobile Money — Bénin */
    readonly MTN_BJ: "MTN_BJ";
    /** Orange Money — RD Congo */
    readonly OM_CD: "OM_CD";
    /** Airtel Money — RD Congo */
